import React, { useState } from 'react';

const Tasks = () => {
  const [taskInput, setTaskInput] = useState('');
  const [tasks, setTasks] = useState([]);

  const addTask = () => {
    if (taskInput.trim() === '') return;
    const newTask = {
      id: Date.now(),
      title: taskInput,
      items: [],
    };
    setTasks([...tasks, newTask]);
    setTaskInput('');
  };

  const addItemToTask = (taskId) => {
    const itemText = prompt('Add sub-task:');
    if (itemText) {
      setTasks(prev =>
        prev.map(task =>
          task.id === taskId
            ? { ...task, items: [...task.items, { text: itemText, checked: false }] }
            : task
        )
      );
    }
  };

  const toggleCheckbox = (taskId, index) => {
    setTasks(prev =>
      prev.map(task =>
        task.id === taskId
          ? {
              ...task,
              items: task.items.map((item, idx) =>
                idx === index ? { ...item, checked: !item.checked } : item
              ),
            }
          : task
      )
    );
  };

  const deleteTask = (taskId) => {
    setTasks(tasks.filter(task => task.id !== taskId));
  };

  const editTaskTitle = (taskId) => {
    const newTitle = prompt('Edit task title:');
    if (newTitle) {
      setTasks(prev =>
        prev.map(task =>
          task.id === taskId ? { ...task, title: newTitle } : task
        )
      );
    }
  };

  return (
    <div className="task-page">
      <div className="task-input-row">
        <input
          type="text"
          value={taskInput}
          onChange={(e) => setTaskInput(e.target.value)}
          placeholder="Add Task ...."
          className="task-input"
        />
        <button onClick={addTask} className="add-btn">Add</button>
      </div>

      <div className="task-cards">
        {tasks.map(task => (
          <div key={task.id} className="task-card">
            <div className="task-header">
              <span className="task-title">{task.title}</span>
              <div className="icons">
                <button onClick={() => addItemToTask(task.id)}>➕</button>
                <button onClick={() => editTaskTitle(task.id)}>✏️</button>
                <button onClick={() => deleteTask(task.id)}>🗑️</button>
              </div>
            </div>
            <ul className="task-items">
              {task.items.map((item, index) => (
                <li key={index}>
                  <input
                    type="checkbox"
                    checked={item.checked}
                    onChange={() => toggleCheckbox(task.id, index)}
                  />
                  <span className={item.checked ? 'checked' : ''}>{item.text}</span>
                </li>
              ))}
            </ul>
          </div>
        ))}
      </div>
      <Stylesheet/>
    </div>
  );
};

const Stylesheet=()=>{
  return <style>{`
  :root {
  --text: #7e5f40;
  --bg-parchment: #f5e6c8;
  --secondary-color: #d6b98c;
  --button-border: #5a4432;
  --font-text: #4b3621;
  --text-light: #7a6651;
  --accent-lavender: #8c6fc3;
  --button-color: #7b8b58;
  --flower-white: #fdfaf5;
}

.task-page {
  padding: 2rem;
  font-family: 'Cedarville Cursive', cursive;
  background-image: url('/path/to/your/botanical-background.png');
  background-size: cover;
  background-position: center;
}

.task-input-row {
  display: flex;
  justify-content: center;
  gap: 1rem;
  margin-bottom: 2rem;
}

.task-input {
  padding: 1rem 1.5rem;
  font-size: 1.3rem;
  border: 2px solid var(--button-border);
  border-radius: 10px;
  width: 300px;
  background: var(--flower-white);
  color: var(--font-text);
  font-family: 'Cedarville Cursive', cursive;
}

.add-btn {
  padding: 0.8rem 1.5rem;
  background-color: var(--secondary-color);
  color: var(--font-text);
  border: 2px solid var(--button-border);
  border-radius: 10px;
  font-size: 1.2rem;
  cursor: pointer;
  font-family: 'Cedarville Cursive', cursive;
}

.task-cards {
  display: flex;
  justify-content: space-evenly;
  flex-wrap: wrap;
  gap: 2rem;
}

.task-card {
  background-color: var(--secondary-color);
  border: 2px solid var(--button-border);
  padding: 1rem;
  border-radius: 12px;
  width: 220px;
  color: var(--font-text);
}

.task-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.icons button {
  background: none;
  border: none;
  font-size: 1.1rem;
  margin-left: 5px;
  cursor: pointer;
  color: var(--font-text);
}

.task-title {
  font-size: 1.2rem;
  font-weight: bold;
}

.task-items {
  margin-top: 1rem;
  list-style: none;
  padding: 0;
}

.task-items li {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin: 0.3rem 0;
}

.checked {
  text-decoration: line-through;
  color: var(--text-light);
}
  
  `}</style>
}

export default Tasks;
